- (void)tryToConnectBle{
    if (self.viewModel.isAuthorized) {
        DLogTagInfo(kBLEParkingTag, @"no need to ConnectBle");
        return;
    }
    DLogTagInfo(kBLEParkingTag, @"tryToConnectBle");
    if (CTMediator.isSDK2ndCar) {
        [XPVehicleSDK.shared.vehicleManager.currentVehicle connectWithChannel:XPVehicleChannelBLE];
        DLogTagInfo(kBLEParkingTag, @"sdk调用连接蓝牙");
        return;
    }
    [XPToast showLoadingMessage:XP_CAR_CONTROL_LOCALIZED_STRING(@"parking_car_under_connecting", nil)];

    @weakify(self)
    __weak typeof(self) weakSelf = self;
    [[self.viewModel tryToConnectBLE].deliverOnMainThread subscribeError:^(NSError * _Nullable error) {
        DLogTagInfo(kBLEParkingTag, @"自动泊车蓝牙连接失败,error=%@",error);
        [XPToast dismissLoadingMessage];
        if ([XPBLEHandlerManager.manager getCommuicateBLEConnectState] == XPBLEHanderConnectStateConnecting) {
            RACCompoundDisposable* dispose = [RACCompoundDisposable compoundDisposable];
            [dispose addDisposable:({
                [XPBLEHandlerManager.manager.sendBleConnectStateSingal subscribeNext:^(NSNumber*  _Nullable x) {
                    NSDictionary *stateDict = (NSDictionary *)x;
                    XPBLEHanderConnectState state = [stateDict[XP_BLEKEY_CONNECT_STATE_KEY] intValue];
                    BOOL isCommunicate = [stateDict[XP_BLEKEY_IS_COMMUNICATE_KEY] boolValue];
                    if (!isCommunicate) {
                        return;
                    }
                    if (XPBLEHanderConnectStateDisconnect == state) {
                        __IF_DO(![dispose isDisposed], [dispose dispose])
                    } else if (XPBLEHanderConnectStateAuthorized == state) {
                        @strongify(self)
                        RACCompoundDisposable* cd = [RACCompoundDisposable compoundDisposable];
                        [cd addDisposable:[[RACObserve(weakSelf.viewModel, isTimerRunningFlag) takeUntil:weakSelf.rac_willDeallocSignal] subscribeNext:^(NSNumber*  _Nullable value) {
                            if (![value boolValue]) {
                                [cd dispose];
                                [XPToast showMessage:XP_CAR_CONTROL_LOCALIZED_STRING(@"parking_car_under_connected", nil)];
                                [self.viewModel updateIsAuthorized:YES];
                                [weakSelf bindTimer];
                            }
                        }]];
                        __IF_DO(![dispose isDisposed], [dispose dispose])
                    }
                }];
            })];
        } else {
            if (![NSString isEmptyWithString:error.localizedFailureReason]) {
                [XPToast showMessage:error.localizedFailureReason];
            }
        }
    } completed:^{
        DLogTagInfo(kBLEParkingTag, @"自动泊车蓝牙连接成功");
        [XPToast dismissLoadingMessage];
        @strongify(self)
        RACCompoundDisposable* cd = [RACCompoundDisposable compoundDisposable];
        [cd addDisposable:[[RACObserve(weakSelf.viewModel, isTimerRunningFlag) takeUntil:weakSelf.rac_willDeallocSignal] subscribeNext:^(NSNumber*  _Nullable value) {
            if (![value boolValue]) {
                [cd dispose];
                [XPToast showMessage:XP_CAR_CONTROL_LOCALIZED_STRING(@"parking_car_under_connected", nil)];
                [self.viewModel updateIsAuthorized:YES];
                [weakSelf bindTimer];
            }
        }]];
    }];
}

