        DLogTagInfo(kBLESmartParkingTag,@"SDK智能出库收到信号%@", bleParkInfo);
        if (bleParkInfo.parkOutDirectionIfOk == 1) {
            self.isAvalable = XPParkingOutAvalableYES;
        } else {
            self.isAvalable = XPParkingOutAvalableNO;
        }
        self.parkingState = bleParkInfo.parkOutState;

        if (self.parkingState == XPAppParkingOutCurrentStateOnLine) {
            self.parkingOutAvalableDirection = bleParkInfo.parkOutAvailableDirection;
        }

        [self bleTransToApvoice:self.parkingState];
        [self handleApvoiceStatus];
        DLogTagInfo(kBLESmartParkingTag,@"SDK回退到开始的页面，顺便给方向可用提示");
        [self showParkingOutResult];

        [self addCamera];

        DLogTagInfo(kBLESmartParkingTag,@"收到泊车失败原因，failcode %ld", (long)bleParkInfo.failCode);
        [self onParkingExpUpdate:(XPAppAutoParkingExpType)bleParkInfo.failCode];

    });
}] bind:self];

